import React, { useState, useEffect } from "react";
import useStore from "../context/store";
import { doctorService } from "../services/api";
import { generateSlots, formatHour, buildSlot, todayStr } from "../utils/helpers";
import Spinner from "./Spinner";

const inputStyle = {
  width: "100%",
  background: "#020810",
  border: "1px solid #0d3a5c",
  borderRadius: 8,
  padding: "10px 14px",
  color: "#cfd8dc",
  fontFamily: "'DM Mono', monospace",
  fontSize: 14,
  boxSizing: "border-box",
  outline: "none",
};

const labelStyle = {
  display: "block",
  color: "#546e7a",
  fontFamily: "'DM Mono', monospace",
  fontSize: 12,
  letterSpacing: 1,
  textTransform: "uppercase",
  marginBottom: 6,
};

const errorStyle = { color: "#ff4d6d", fontSize: 12, marginTop: 4, fontFamily: "'DM Mono', monospace" };

export default function BookAppointmentForm({ onSuccess, preselectedDoctorId }) {
  const { doctors, bookAppointment } = useStore();

  const [form, setForm] = useState({
    doctor_id: preselectedDoctorId || "",
    patient_name: "",
    date: todayStr(),
    hour: "",
  });
  const [errors, setErrors] = useState({});
  const [bookedSlots, setBookedSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState("");

  const selectedDoctor = doctors.find((d) => d.id === Number(form.doctor_id));

  useEffect(() => {
    if (!form.doctor_id || !form.date) return;
    doctorService.getBookedSlots(form.doctor_id, form.date)
      .then(setBookedSlots)
      .catch(() => setBookedSlots([]));
  }, [form.doctor_id, form.date]);

  const validate = () => {
    const errs = {};
    if (!form.doctor_id) errs.doctor_id = "Please select a doctor";
    if (!form.patient_name || form.patient_name.trim().length < 2)
      errs.patient_name = "Patient name must be at least 2 characters";
    if (!form.date || form.date < todayStr())
      errs.date = "Date cannot be in the past";
    if (!form.hour && form.hour !== 0)
      errs.hour = "Please select a time slot";
    return errs;
  };

  const handleSubmit = async () => {
    const errs = validate();
    setErrors(errs);
    if (Object.keys(errs).length > 0) return;
    setLoading(true);
    setApiError("");
    try {
      await bookAppointment({
        doctor_id: Number(form.doctor_id),
        patient_name: form.patient_name.trim(),
        slot: buildSlot(form.date, form.hour),
      });
      setForm({ doctor_id: preselectedDoctorId || "", patient_name: "", date: todayStr(), hour: "" });
      setErrors({});
      onSuccess && onSuccess();
    } catch (e) {
      setApiError(e.response?.data?.detail || "Booking failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const availableSlots = selectedDoctor
    ? generateSlots(selectedDoctor.start_hour, selectedDoctor.end_hour)
    : [];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
      {/* Doctor */}
      <div>
        <label style={labelStyle}>Doctor</label>
        <select
          style={inputStyle}
          value={form.doctor_id}
          onChange={(e) => setForm((f) => ({ ...f, doctor_id: e.target.value, hour: "" }))}
        >
          <option value="">— Select a doctor —</option>
          {doctors.map((d) => (
            <option key={d.id} value={d.id}>
              {d.name} · {d.specialization}
            </option>
          ))}
        </select>
        {errors.doctor_id && <p style={errorStyle}>{errors.doctor_id}</p>}
      </div>

      {/* Patient Name */}
      <div>
        <label style={labelStyle}>Patient Name</label>
        <input
          style={inputStyle}
          placeholder="Full name"
          value={form.patient_name}
          onChange={(e) => setForm((f) => ({ ...f, patient_name: e.target.value }))}
        />
        {errors.patient_name && <p style={errorStyle}>{errors.patient_name}</p>}
      </div>

      {/* Date */}
      <div>
        <label style={labelStyle}>Date</label>
        <input
          type="date"
          style={inputStyle}
          value={form.date}
          min={todayStr()}
          onChange={(e) => setForm((f) => ({ ...f, date: e.target.value, hour: "" }))}
        />
        {errors.date && <p style={errorStyle}>{errors.date}</p>}
      </div>

      {/* Time Slot */}
      {selectedDoctor && (
        <div>
          <label style={labelStyle}>Time Slot</label>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8 }}>
            {availableSlots.map((h) => {
              const booked = bookedSlots.includes(String(h));
              const selected = Number(form.hour) === h;
              return (
                <button
                  key={h}
                  disabled={booked}
                  onClick={() => !booked && setForm((f) => ({ ...f, hour: h }))}
                  style={{
                    padding: "8px 4px",
                    borderRadius: 7,
                    border: selected ? "1px solid #00bcd4" : "1px solid #0d3a5c",
                    background: booked ? "#0a1a27" : selected ? "#003a4a" : "#020810",
                    color: booked ? "#263238" : selected ? "#00e5ff" : "#78909c",
                    fontFamily: "'DM Mono', monospace",
                    fontSize: 12,
                    cursor: booked ? "not-allowed" : "pointer",
                    textDecoration: booked ? "line-through" : "none",
                  }}
                  title={booked ? "Already booked" : ""}
                >
                  {formatHour(h)}
                </button>
              );
            })}
          </div>
          {errors.hour && <p style={errorStyle}>{errors.hour}</p>}
        </div>
      )}

      {apiError && (
        <div style={{ background: "#2e0d0d", border: "1px solid #ff4d6d", borderRadius: 8, padding: "10px 14px" }}>
          <p style={{ ...errorStyle, margin: 0 }}>{apiError}</p>
        </div>
      )}

      <button
        onClick={handleSubmit}
        disabled={loading}
        style={{
          marginTop: 4,
          padding: "12px 0",
          background: loading ? "#0d3a5c" : "linear-gradient(135deg, #006080, #00bcd4)",
          border: "none",
          borderRadius: 9,
          color: "#fff",
          fontFamily: "'Syne', sans-serif",
          fontSize: 15,
          fontWeight: 700,
          cursor: loading ? "not-allowed" : "pointer",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          gap: 10,
        }}
      >
        {loading ? <><Spinner size={18} /> Booking…</> : "Confirm Appointment"}
      </button>
    </div>
  );
}
